import { z } from 'zod';

const envSchema = z.object({
  PORT: z.string().regex(/^\d+$/, 'PORT must be a number between 1024 and 65535'),
  DATABASE_URL: z.string().url(),
  JWT_SECRET: z.string().min(32, 'JWT_SECRET must be at least 32 characters'),
  RATE_LIMIT_MAX: z.string().regex(/^\d+$/, 'RATE_LIMIT_MAX must be a numeric value'),
  RATE_LIMIT_WINDOW: z.string().regex(/^\d+m$/, 'RATE_LIMIT_WINDOW must be in the format "10m"'),
});

envSchema.parse(process.env);

export default envSchema;

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';

const corsOptions = {
  origin: function(origin, callback) {
    if (!origin || process.env.CORS_WHITELIST?.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  },
  credentials: true, // Allows cookies to be sent
};

const rateLimitOptions = rateLimit({
  windowMs: parseInt(process.env.RATE_LIMIT_WINDOW || \
                     '15m') * 60 * 1000, // convert minutes to ms
  max: parseInt(process.env.RATE_LIMIT_MAX || '100'),
  message: 'Too many requests from this IP, please try again later.',
});

export default {
  helmet: helmet(),
  cors: cors(corsOptions),
  rateLimit: rateLimitOptions,
};

import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';

export function errorHandler(err: any, req: Request, res: Response, next: NextFunction) {
  let customError = {
    // set default error
    statusCode: err.statusCode || 500,
    message: err.message || 'Internal Server Error',
  };

  if (err instanceof ZodError) {
    customError.message = 'Validation Error';
    res.status(400).json({
      message: customError.message,
      errors: err.errors.map(e => ({
        path: e.path.join('.'),
        message: e.message,
    })),
    });
    return;
  }

  res.status(customError.statusCode).json({
    message: customError.message,
  });
}

import { ObjectId } from 'mongodb';

export interface UserDto {
  id: string;
  username: string;
  email: string;
  createdAt: string;
}

export const mapUserToDto = (user: { id: ObjectId; username: string; email: string; createdAt: Date; }): UserDto => {
  return {
    id: user.id.toHexString(),
    username: user.username,
    email: user.email,
    createdAt: user.createdAt.toISOString(),
  };
};
